import React from 'react';

const Assets: React.FC = () => {
  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold tracking-tight">Asset Inventory</h2>
      <p className="text-gray-500">Manage and monitor your infrastructure assets here.</p>

      <div className="rounded-md border bg-card p-8 text-center text-gray-500">
        No assets configured yet. Connect a SIEM source to begin discovering endpoints.
      </div>
    </div>
  );
};

export default Assets;
